    10→import { useAuth } from "@/providers/auth-provider";
    11→import { useProfile } from "@/hooks/use-profile";
    12→import { useLanguageStore } from "@/store/language-store";
    13→import { cn } from "@/lib/utils";
    14→import { toast } from "sonner";
    15→
    16→interface Project {
    17→    id: string;
    18→    title?: string;
    19→    text: string;
    20→    description?: string;
    21→    color?: string;
    22→    globalScore?: number;
    23→    recommendation?: string;
    24→    confidenceLevel?: string;
    25→    viabilityScore?: number;
    26→    classification?: string;
    27→    timestamp: string;
    28→    isDemo?: boolean;
    29→    isArchived?: boolean;
    30→    analysis?: any;
    31→}
    32→
    33→function getProjectDecision(p: Project): string {
    34→    return p.recommendation ?? p.classification ?? "DRAFT";
    35→}
    36→
    37→function getProjectTitle(p: Project): string {
    38→    return p.title ?? p.text;
    39→}
    40→
    41→export default function WorkspacePage() {
    42→    const router = useRouter();
    43→    const { user } = useAuth();
    44→    const { profile } = useProfile();
    45→    const { t } = useLanguageStore();
    46→
    47→    const [projects, setProjects] = useState<Project[]>([]);
    48→    const [searchQuery, setSearchQuery] = useState("");
    49→    const [activeFilter, setActiveFilter] = useState<string>("ALL");
    50→    const [sortBy, setSortBy] = useState<string>("date");
    51→    const [showArchived, setShowArchived] = useState(false);
    52→
    53→    // Detail overlay state
    54→    const [detailProject, setDetailProject] = useState<Project | null>(null);
    55→    const [detailOpen, setDetailOpen] = useState(false);
    56→
    57→    // Initial Load Logic
    58→    useEffect(() => {
    59→        const currentIdea = localStorage.getItem("k3rn_active_project");
    60→        const storedProjects = JSON.parse(localStorage.getItem("k3rn_projects") || "[]");
    61→
    62→        if (currentIdea) {
    63→            const idea = JSON.parse(currentIdea);
    64→            const exists = storedProjects.some((p: any) => p.timestamp === idea.timestamp);
    65→            if (!exists) {
    66→                const newProject: Project = {
    67→                    id: idea.id || crypto.randomUUID(),
    68→                    title: idea.title,
    69→                    text: idea.text || "",
    70→                    description: idea.description,
    71→                    globalScore: idea.globalScore ?? idea.analysis?.viabilityScore,
    72→                    recommendation: idea.recommendation ?? idea.analysis?.classification,
    73→                    confidenceLevel: idea.confidenceLevel,
    74→                    viabilityScore: idea.viabilityScore ?? idea.analysis?.viabilityScore,
    75→                    classification: idea.classification ?? idea.analysis?.classification,
    76→                    timestamp: idea.timestamp,
    77→                    isDemo: idea.isDemo,
    78→                    analysis: idea.analysis,
    79→                };
    80→                storedProjects.unshift(newProject);
    81→                localStorage.setItem("k3rn_projects", JSON.stringify(storedProjects));
    82→                localStorage.removeItem("k3rn_active_project");
    83→            }
    84→        }
    85→
    86→        if (storedProjects.length === 0) {
    87→            const mocks: Project[] = [
    88→                { id: "1", title: "Drone Fleet SaaS Platform", text: "Plateforme SaaS de gestion de flottes de drones autonomes", globalScore: 92, recommendation: "GO", confidenceLevel: "HIGH", timestamp: new Date().toISOString(), isDemo: true, description: "A comprehensive solution for autonomous drone logistics, featuring real-time telemetry, AI-driven pathfinding, and predictive maintenance.", analysis: { axes: [{ label: "Probleme", score: 9 }, { label: "Marche", score: 8 }, { label: "Differenciation", score: 10 }, { label: "Faisabilite", score: 8 }, { label: "Business Model", score: 9 }, { label: "Founder Fit", score: 9 }], synthesis: "Ce projet presente un potentiel exceptionnel. Le marche de la logistique drone est en pleine expansion avec un CAGR de 28%. La differenciation technique est maximale grace a l'integration d'IA pour le pathfinding et la maintenance predictive. Le business model SaaS assure des revenus recurrents. Recommandation : accelerer le developpement du MVP et securiser un premier contrat pilote.", risks: ["Reglementation aerienne complexe et en evolution — risque de delais reglementaires", "Cout d'infrastructure eleve pour le deploiement initial (stations de charge, communication)", "Competition potentielle des geants tech (Amazon Prime Air, Wing/Alphabet)", "Dependance aux conditions meteorologiques pour les operations quotidiennes"] } },
    89→                { id: "2", title: "NFT Patent Marketplace", text: "Marketplace NFT pour brevets industriels", globalScore: 38, recommendation: "KILL", confidenceLevel: "HIGH", timestamp: new Date(Date.now() - 86400000).toISOString(), isDemo: true, description: "Attempting to tokenize IP rights on the blockchain. Initial market validation suggests low demand.", analysis: { synthesis: "Le concept de tokenisation des brevets sur blockchain ne repond pas a un besoin reel du marche. Les acteurs industriels privilegient les canaux traditionnels de gestion de PI.", risks: ["Absence de demande marche validee", "Complexite juridique de la tokenisation de PI", "Modele economique non viable a long terme"] } },
    90→                { id: "3", title: "AI Film Script Generator", text: "IA generative pour scripts de films", globalScore: 78, recommendation: "EXPLORE", confidenceLevel: "MEDIUM", timestamp: new Date(Date.now() - 172800000).toISOString(), isDemo: true, description: "Leveraging LLMs for creative writing assistance. The prototype shows promise but lacks structure.", analysis: { synthesis: "L'outil montre un potentiel creatif interessant mais necessite une structuration plus poussee du workflow narratif. Le marche de l'IA creative est en croissance rapide.", risks: ["Qualite narrative encore insuffisante pour un usage professionnel", "Concurrence forte des outils existants (ChatGPT, Jasper)", "Questions ethiques sur la propriete intellectuelle generee par IA"] } },
    91→                { id: "4", title: "MeowNet - Social Network for Cats", text: "Reseau social pour chats (MeowNet)", globalScore: 22, recommendation: "PARK", confidenceLevel: "LOW", timestamp: new Date(Date.now() - 432000000).toISOString(), isDemo: true, description: "Niche social network. Market size is questionable despite high engagement potential." },
    92→                { id: "5", title: "Quantum Encryption Key", text: "Cle de chiffrement quantique", globalScore: 88, recommendation: "GO", confidenceLevel: "HIGH", timestamp: new Date(Date.now() - 500000000).toISOString(), isDemo: true, description: "Next-gen security infrastructure for fintech. Critical need in the post-quantum era.", analysis: { axes: [{ label: "Probleme", score: 10 }, { label: "Marche", score: 9 }, { label: "Differenciation", score: 8 }, { label: "Faisabilite", score: 7 }, { label: "Business Model", score: 9 }, { label: "Founder Fit", score: 8 }], synthesis: "Infrastructure de securite critique pour l'ere post-quantique. Le marche fintech est pret pour cette transition. La faisabilite technique est le principal defi.", risks: ["Complexite technique de l'implementation quantique", "Cout de R&D eleve avant commercialisation", "Risque de timing — marche pas encore pret massivement"] } },
    93→            ];
    94→            setProjects(mocks);
    95→        } else {
    96→            setProjects(storedProjects);
    97→        }
    98→    }, []);
    99→
   100→    const filteredProjects = useMemo(() => {
   101→        let result = projects.filter((p) => {
   102→            // Filter by archived status
   103→            const matchesArchiveStatus = showArchived ? p.isArchived === true : p.isArchived !== true;
   104→
   105→            const q = searchQuery.toLowerCase();
   106→            const matchesSearch =
   107→                getProjectTitle(p).toLowerCase().includes(q) ||
   108→                p.text.toLowerCase().includes(q) ||
   109→                getProjectDecision(p).toLowerCase().includes(q);
   110→
   111→            const matchesFilter = activeFilter === "ALL" || getProjectDecision(p) === activeFilter;
   112→
   113→            return matchesArchiveStatus && matchesSearch && matchesFilter;
   114→        });
   115→
   116→        if (sortBy === "score") {
   117→            result = [...result].sort((a, b) => (b.globalScore ?? 0) - (a.globalScore ?? 0));
   118→        } else {
   119→            result = [...result].sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
   120→        }
   121→
   122→        return result;
   123→    }, [projects, searchQuery, activeFilter, sortBy, showArchived]);
   124→
   125→    // Welcome hero stats
   126→    const goCount = projects.filter((p) => getProjectDecision(p) === "GO").length;
   127→    const attentionCount = projects.filter((p) => {
   128→        const d = getProjectDecision(p);
   129→        return d === "EXPLORE" || d === "KILL";
   130→    }).length;
   131→
   132→    // Save handler for detail overlay
   133→    function handleSaveProject(id: string, updates: { title?: string; description?: string }) {
   134→        const updated = projects.map((p) =>
   135→            p.id === id ? { ...p, ...updates } : p
   136→        );
   137→        setProjects(updated);
   138→        localStorage.setItem("k3rn_projects", JSON.stringify(updated));
   139→        // Update detailProject so the overlay reflects saved data
   140→        if (detailProject && detailProject.id === id) {
   141→            setDetailProject({ ...detailProject, ...updates });
   142→        }
   143→        toast.success("Dossier sauvegardé");
   144→    }
   145→
   146→    // Archive handler
   147→    function handleArchive(id: string) {
   148→        const updated = projects.map((p) =>
   149→            p.id === id ? { ...p, isArchived: true } : p
   150→        );
   151→        setProjects(updated);
   152→        localStorage.setItem("k3rn_projects", JSON.stringify(updated));
   153→        setDetailOpen(false);
   154→        setDetailProject(null);
   155→    }
   156→
   157→    // Unarchive handler
   158→    function handleUnarchive(id: string) {
   159→        const updated = projects.map((p) =>
   160→            p.id === id ? { ...p, isArchived: false } : p
   161→        );
   162→        setProjects(updated);
   163→        localStorage.setItem("k3rn_projects", JSON.stringify(updated));
   164→        setDetailOpen(false);
   165→        setDetailProject(null);
   166→    }
   167→
   168→    // Delete handler
   169→    function handleDelete(id: string) {
   170→        const updated = projects.filter((p) => p.id !== id);
   171→        setProjects(updated);
   172→        localStorage.setItem("k3rn_projects", JSON.stringify(updated));
   173→        setDetailOpen(false);
   174→        setDetailProject(null);
   175→    }
   176→
   177→    // Item size state with persistence
   178→    const [itemSize, setItemSize] = useState(360);
   179→    const [isLoaded, setIsLoaded] = useState(false);
   180→
   181→    useEffect(() => {
   182→        const savedSize = localStorage.getItem("k3rn_card_size");
   183→        if (savedSize) {
   184→            setItemSize(Number(savedSize));
   185→        }
   186→        setIsLoaded(true);
   187→    }, []);
   188→
   189→    useEffect(() => {
   190→        if (isLoaded) {
   191→            localStorage.setItem("k3rn_card_size", itemSize.toString());
   192→        }
   193→    }, [itemSize, isLoaded]);
   194→
   195→    return (
   196→        <div className="min-h-screen bg-background text-foreground font-sans selection:bg-[--color-brand-primary]/30 flex flex-col overflow-x-hidden">
   197→            <SiteHeader variant="app" />
   198→
   199→            <main className="relative z-[1] flex-1 pt-24 pb-40 px-8 w-full max-w-[1400px] mx-auto">
   200→
   201→                {/* Welcome Hero */}
   202→                <div
   203→                    className="mb-12 rounded-[var(--radius-2xl)] p-8 animate-in fade-in slide-in-from-bottom-4 duration-500"
   204→                    style={{
   205→                        background: "var(--color-bg-secondary)",
   206→                        border: "1px solid var(--color-border-subtle)",
   207→                    }}
   208→                >
   209→                    <h1 className="text-[2.5rem] font-light text-white tracking-[-0.02em] leading-[1.1] mb-3">
   210→                        Bonjour, <span className="text-white">{user?.user_metadata?.full_name?.split(' ')[0] || user?.user_metadata?.full_name || "l'ami"}</span>.
   211→                    </h1>
   212→                    <div className="flex items-center justify-between">
   213→                        <p className="text-base text-[--color-text-muted] flex items-center gap-2">
   214→                            <strong className="text-[--color-text-secondary] font-medium">{projects.filter(p => !p.isArchived).length}</strong> dossier{projects.filter(p => !p.isArchived).length !== 1 ? "s" : ""} actif{projects.filter(p => !p.isArchived).length !== 1 ? "s" : ""}
   215→                            {" "}&middot;{" "}
   216→                            <strong className="text-[--color-text-secondary] font-medium">{goCount}</strong> projet{goCount !== 1 ? "s" : ""} valide{goCount !== 1 ? "s" : ""} GO
   217→                            {" "}&middot;{" "}
   218→                            <strong className="text-[--color-text-secondary] font-medium">{attentionCount}</strong> necessite{attentionCount !== 1 ? "nt" : ""} votre attention
   219→                        </p>
   220→                        <button
   221→                            onClick={() => setShowArchived(!showArchived)}
   222→                            className="group inline-flex items-center gap-2 px-4 py-2 bg-transparent text-[--color-text-muted] border border-[--color-border-default] rounded-[var(--radius-md)] text-sm font-medium transition-all duration-300 hover:text-white hover:bg-[rgba(255,255,255,0.06)] hover:border-[--color-border-strong] hover:scale-[1.02] active:scale-[0.98]"
   223→                        >
   224→                            <Archive className="w-4 h-4 transition-transform duration-300 group-hover:scale-110" />
   225→                            {showArchived ? "Dossiers actifs" : "Dossiers archivés disponibles"}
   226→                        </button>
   227→                    </div>
   228→                </div>
   229→
   230→                {/* Grid */}
   231→                <div className={cn(
   232→                    "animate-in fade-in zoom-in-95 duration-500",
   233→                    "grid gap-6"
   234→                )}
   235→                    style={{ gridTemplateColumns: `repeat(auto-fill, minmax(${itemSize}px, 1fr))` }}
   236→                >
   237→                    {/* New Project Card - Only show when NOT in archived view */}
   238→                    {!showArchived && (
   239→                        <ProCard
   240→                            isNew
   241→                            size={itemSize}
   242→                            onClick={() => router.push('/capture')}
   243→                        />
   244→                    )}
   245→
   246→                    {/* Project Cards */}
   247→                    {filteredProjects.map((project) => (
   248→                        <ProCard
   249→                            key={project.id}
   250→                            project={project}
   251→                            size={itemSize}
   252→                            onClick={() => {
   253→                                setDetailProject(project);
   254→                                setDetailOpen(true);
   255→                            }}
   256→                        />
   257→                    ))}
   258→                </div>
   259→            </main>
   260→
   261→            {/* Floating Command Dock */}
   262→            <FloatingDock
   263→                searchQuery={searchQuery}
   264→                setSearchQuery={setSearchQuery}
   265→                activeFilter={activeFilter}
   266→                setActiveFilter={setActiveFilter}
   267→                sortBy={sortBy}
   268→                setSortBy={setSortBy}
   269→                itemSize={itemSize}
   270→                setItemSize={setItemSize}
   271→                onNewProject={() => router.push('/capture')}
   272→            />
   273→
   274→            {/* Project Detail Overlay */}
   275→            <ProjectDetailOverlay
   276→                project={detailProject}
   277→                open={detailOpen}
   278→                onClose={() => {
   279→                    setDetailOpen(false);
   280→                    setDetailProject(null);
   281→                }}
   282→                onSave={handleSaveProject}
   283→                onArchive={handleArchive}
   284→                onUnarchive={handleUnarchive}
   285→                onDelete={handleDelete}
   286→            />
   287→        </div>
   288→    );
   289→}
