     1→"use client";
     2→
     3→import { cn } from "@/lib/utils";
     4→import { Folder, FolderOpen, Clock, Plus, ArrowUpRight } from "lucide-react";
     5→import { DecisionBadge } from "@/components/ui/decision-badge";
     6→
     7→interface Project {
     8→    id: string;
     9→    title?: string;
    10→    text: string;
    11→    description?: string;
    12→    globalScore?: number;
    13→    recommendation?: string;
    14→    timestamp: string;
    15→    color?: string;
    16→}
    17→
    18→interface ProCardProps {
    19→    project?: Project;
    20→    isNew?: boolean;
    21→    onClick?: () => void;
    22→    className?: string;
    23→    size?: number;
    24→}
    25→
    26→const DECISION_COLORS: Record<string, string> = {
    27→    GO: "#22C55E",
    28→    EXPLORE: "#F59E0B",
    29→    PARK: "#6B7280",
    30→    KILL: "#EF4444",
    31→    DRAFT: "#6C6F78",
    32→};
    33→
    34→export function ProCard({ project, isNew, onClick, className, size = 360 }: ProCardProps) {
    35→    // Responsive breakpoints
    36→    const isTiny = size < 180;
    37→    const isCompact = size < 250;
    38→    const isSmall = size < 300;
    39→
    40→    if (isNew) {
    41→        return (
    42→            <div
    43→                onClick={onClick}
    44→                className={cn(
    45→                    "group relative w-full cursor-pointer h-full aspect-[3/2]",
    46→                    "bg-[#1A1D24] rounded-[var(--radius-xl)] border border-dashed border-[#3A3D45]",
    47→                    "hover:border-[#525252] hover:bg-[#22242B] hover:-translate-y-0.5",
    48→                    "transition-all duration-300 ease-out flex flex-col items-center justify-center",
    49→                    isCompact ? "gap-2" : "gap-4",
    50→                    className
    51→                )}
    52→            >
    53→                <div
    54→                    className={cn(
    55→                        "rounded-full bg-[#22242B] border border-[#3A3D45] flex items-center justify-center transition-all duration-300 group-hover:scale-105 group-hover:border-[#525252] group-hover:bg-[#2A2D35]",
    56→                        isTiny ? "w-8 h-8" : isCompact ? "w-10 h-10" : "w-12 h-12"
    57→                    )}
    58→                >
    59→                    <Plus className={cn("text-[#71717A] group-hover:text-white transition-colors duration-300", isTiny ? "w-3 h-3" : "w-5 h-5")} />
    60→                </div>
    61→                <span className={cn(
    62→                    "font-bold text-[#71717A] group-hover:text-white uppercase tracking-[0.15em] transition-colors duration-300 text-center",
    63→                    isTiny ? "text-[8px] leading-tight px-1" : "text-xs"
    64→                )}>
    65→                    {isTiny ? "Nouveau" : "Nouveau Dossier"}
    66→                </span>
    67→            </div>
    68→        );
    69→    }
    70→
    71→    if (!project) return null;
    72→
    73→    const decision = project.recommendation || "DRAFT";
    74→    const score = project.globalScore || 0;
    75→    const accentColor = project.color || DECISION_COLORS[decision] || DECISION_COLORS.DRAFT;
    76→
    77→    return (
    78→        <div
    79→            onClick={onClick}
